<template>
  <div class="sign">
    <transition name="fade">
      <Message v-if="messagePopup" @closeMessagePopup="closeMessagePopup" :title="message.title"
               :description="message.description"/>
    </transition>
    <div class="container sign__content">
      <h2 class="sign__title">Регистрация</h2>
      <form @submit.prevent="signIn" class="sign__form">
        <input type="text" placeholder="Login" v-model="form.login">
        <input type="password" placeholder="Password" v-model="form.password">
        <input type="password" placeholder="Confirm the password" v-model="form.confirmPassword">
        <button type="submit">Зарегистрироваться</button>
        <router-link to="/sign-in" class="sign__reg" tag="div">Войти</router-link>
      </form>

    </div>
    <Nav/>
  </div>
</template>

<script>
import Nav from "@/components/Nav.vue";
import Message from "@/components/Message.vue";

export default {
  components: {
    Nav,
    Message,
  },
  data() {
    return {
      form: {
        login: '',
        password: '',
        confirmPassword: '',
      },
      messagePopup: false,
      message: {
        title: 'Ошибка',
        description: 'Ошибка валидации',
      }
    }
  },
  computed: {
    apiUrl() {
      return this.$store.getters.apiUrl;
    },
    token() {
      return this.$store.getters.token;
    }
  },
  mounted() {
    if (this.token.length) {
      this.$router.push('/profile')
    }
  },
  methods: {
    async signIn() {
      if (this.form.password == this.form.confirmPassword) {
        const response = await fetch(`${this.apiUrl}/api/account/register`, {
          method: "POST",
          headers: {
            'Content-Type': 'application/json'
          },
          body: JSON.stringify({
            username: this.form.login,
            password: this.form.password,
          }),
        })
        if (response.ok) {
          console.log(response);
          this.$router.push('/sign-in');
        } else {
          const status = await response.json();
          this.messagePopup = true
          if (status.message) {
            this.message.description = status.message;
          } else {
            this.message.description = 'Логин и пароль обязательны';
          }
          console.log(status)
        }
      } else {
        this.messagePopup = true;
        this.message.description = 'Логин и пароль не совпадают';
      }
    },
    closeMessagePopup() {
      this.messagePopup = false;
    }
  }
}
</script>
